float Xrot_point(uint8_t x, uint8_t y)
{
     return mapx[y][x];
}
float Yrot_point(uint8_t x, uint8_t y)
{
     return mapy[y][x];
}
float inv_rot_x(float x, float y)
{
     return ((inv_rot[1][0] * y + inv_rot[1][1] * x + inv_rot[1][2]) / (inv_rot[2][0] * y + inv_rot[2][1] * x + 1));
}
float inv_rot_y(float x, float y)
{
     return ((inv_rot[0][0] * y + inv_rot[0][1] * x + inv_rot[0][2]) / (inv_rot[2][0] * y + inv_rot[2][1] * x + 1));
}
float XShowRotimg(uint8_t x,uint8_t y)
{
return (y*inv_rot[1][0]+x*inv_rot[1][1]+inv_rot[1][2])/(y*inv_rot[2][0]+x*inv_rot[2][1]+inv_rot[2][2]);
}
float YShowRotimg(uint8_t x,uint8_t y)
{
return ((y*inv_rot[0][0]+x*inv_rot[0][1]+inv_rot[0][2]))/(y*inv_rot[2][0]+x*inv_rot[2][1]+inv_rot[2][2]);
}
// 极速逆透视变换（直接映射，无插值）
void nitoushi_fast(const Mat& src, Mat& dst) {
    dst.create(120, 160, src.type());
    
    // 预取图像指针
    uchar* src_ptr = src.data;
    uchar* dst_ptr = dst.data;
    int src_step = src.step;
    int dst_step = dst.step;
    int channels = src.channels();
    
    for (int i = 0; i < 120; i++) {
        for (int j = 0; j < 160; j++) {
            // 计算俯视图坐标（使用您的函数）
            int x = (int)XShowRotimg(j, i);
            int y = (int)YShowRotimg(j, i);
            
            // 边界检查
            if (x >= 0 && x < 160 && y >= 0 && y < 120) {
                // 复制像素
                if (channels == 1) {
                    dst_ptr[i * dst_step + j] = src_ptr[y * src_step + x];
                } else {
                    dst_ptr[i * dst_step + j * 3] = src_ptr[y * src_step + x * 3];
                    dst_ptr[i * dst_step + j * 3 + 1] = src_ptr[y * src_step + x * 3 + 1];
                    dst_ptr[i * dst_step + j * 3 + 2] = src_ptr[y * src_step + x * 3 + 2];
                }
            } else {
                // 超出边界设为0（黑色）
                if (channels == 1) {
                    dst_ptr[i * dst_step + j] = 0;
                } else {
                    dst_ptr[i * dst_step + j * 3] = 0;
                    dst_ptr[i * dst_step + j * 3 + 1] = 0;
                    dst_ptr[i * dst_step + j * 3 + 2] = 0;
                }
            }
        }
    }
}

// 逆变换(俯视->原图)
bool map_inv(float pt0[2], int pt1[2]){    
    int rx = (int)XShowRotimg(pt0[0], pt0[1]);
    int ry = (int)YShowRotimg(pt0[0], pt0[1]);
    if(rx<0 || rx>=160 || ry<0 || ry>=120) return false;
    pt1[0] = rx;
    pt1[1] = ry;
    return true;
}